int count_equal_to_k(int n, int *a, int k)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == count_equal_to_k_spec(l, k) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int ret = 0;

    for (i = 0; i < n; ++i) {
        if (a[i] == k) {
            ret++;
        }
    }

    return ret;
}

